#!/usr/bin/env python3"""Improved JIRA access test to find the 'Discount Code in Cart Bug' issue"""import asyncioimport osimport jsonfrom dotenv import load_dotenvfrom autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchload_dotenv()async def test_improved_jira_access():    """Test JIRA access with improved error handling and broader search."""    def get_required_env(key: str) -> str:        value = os.getenv(key)        if not value:            raise RuntimeError(f"{key} environment variable not found")        return value    jira_server_params = StdioServerParams(        command="uvx",        args=["mcp-atlassian"],        env={            "JIRA_URL": get_required_env("JIRA_URL"),            "JIRA_USERNAME": get_required_env("JIRA_USERNAME"),            "JIRA_API_TOKEN": get_required_env("JIRA_API_TOKEN"),            "TOOLSETS": "all",        },        read_timeout_seconds=60,    )    async with McpWorkbench(jira_server_params) as jira:        print("🔗 Connected to Jira MCP server")        # Search for the specific bug mentioned        print("\n1️⃣ Searching for 'Discount Code in Cart Bug'...")        try:            search_result = await jira.call_tool(                "jira_search",                {                    "jql": "text ~ \"Discount Code\" OR text ~ \"Cart Bug\" OR summary ~ \"Discount\" OR summary ~ \"Cart\"",                    "fields": "summary,status,priority,created,issuetype,description,key",                    "limit": 20                }            )            print(f"Search result type: {type(search_result)}")            print(f"Search result: {search_result}")            if hasattr(search_result, 'result') and search_result.result:                content = search_result.result[0].content                print(f"Raw content: {content}")                try:                    data = json.loads(content)                    total = data.get('total', 0)                    issues = data.get('issues', [])                    print(f"✅ Found {total} issues matching discount/cart criteria")                    for issue in issues:                        key = issue.get('key', 'Unknown')                        summary = issue.get('fields', {}).get('summary', 'No summary')                        status = issue.get('fields', {}).get('status', {}).get('name', 'No status')                        print(f"   🎫 {key}: {summary} [Status: {status}]")                except json.JSONDecodeError as e:                    print(f"❌ JSON decode error: {e}")                    print(f"Content: {content}")            else:                print(f"❌ No results from search")        except Exception as e:            print(f"❌ Error searching for discount bug: {e}")        # Try broad text search        print("\n2️⃣ Broad text search for any issues...")        try:            search_result = await jira.call_tool(                "jira_search",                {                    "jql": "order by created DESC",                    "fields": "summary,status,priority,created,issuetype,key",                    "limit": 20                }            )            if hasattr(search_result, 'result') and search_result.result:                content = search_result.result[0].content                try:                    data = json.loads(content)                    total = data.get('total', 0)                    issues = data.get('issues', [])                    print(f"✅ Found {total} total issues (showing latest 20)")                    for issue in issues:                        key = issue.get('key', 'Unknown')                        summary = issue.get('fields', {}).get('summary', 'No summary')                        status = issue.get('fields', {}).get('status', {}).get('name', 'No status')                        print(f"   🎫 {key}: {summary} [Status: {status}]")                except json.JSONDecodeError as e:                    print(f"❌ JSON decode error: {e}")                    print(f"Content: {content}")            else:                print("❌ No results from broad search")        except Exception as e:            print(f"❌ Error in broad search: {e}")        # List all available tools        print("\n3️⃣ Available JIRA tools...")        try:            tools = await jira.list_tools()            print("Available tools:")            for tool in tools:                print(f"   🔧 {tool.name}: {tool.description}")        except Exception as e:            print(f"❌ Error listing tools: {e}")        # Try getting project info        print("\n4️⃣ Testing project info...")        try:            project_result = await jira.call_tool(                "jira_get_project",                {"key": "KAN"}            )            if hasattr(project_result, 'result') and project_result.result:                content = project_result.result[0].content                print(f"Project info: {content}")                try:                    data = json.loads(content)                    name = data.get('name', 'Unknown')                    key = data.get('key', 'Unknown')                    print(f"✅ Project: {name} ({key})")                except json.JSONDecodeError:                    print("❌ Could not parse project JSON")            else:                print("❌ No project info found")        except Exception as e:            print(f"❌ Error getting project info: {e}")if __name__ == "__main__":    asyncio.run(test_improved_jira_access())